"use client";
import React, { useEffect, useState } from "react";
import { PageProps } from "gatsby";
import { useLocation } from "@reach/router";
import Header from "../../componets/header/Header";
import Footer from "../../componets/footer/Footer";
import EventHero from "../../componets/EventHero/EventHero";
import EventSection from "../../componets/EventAbout/EventAbout";
import SponsorsSection from "../../componets/SponsorsSection/SponsorsSection";
import TestimonialsSection from "../../componets/TestimonialsSection";
import EventSpeakers from "../../componets/EventSpeakers/EventSpeakers";
import PriceList from "../../componets/PriceList/PriceList";
import EventAttendees from "../../componets/EventAttendees/EventAttendees";
import CheckOut from "../../componets/CheckOut";
import { useLanguage } from "../../context/LanguageContext";
import { getContent } from "../../content/content";

interface EventData {
  id: string;
  event: string;
  event_id: string;
  paid: boolean;
  used: string | null;
  is_used: boolean;
  created_at: string;
  about?: any;
  speakers?: any[];
  sponsors?: any[];
  testimonials?: any[];
  pricing?: any[];
  attendees?: any[];
}

const DynamicEventPage: React.FC<PageProps> = () => {
  const location = useLocation();
  const { lang } = useLanguage();
  const content = getContent(lang);
  const eventSlug = location.pathname.split("/")[2]; // e.g. /event/song-viet-nam
  const [eventData, setEventData] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadEvent = () => {
      setLoading(true);

      let baseContent = content;
      // 📝 Support CMS Draft Preview
      try {
        const raw = localStorage.getItem("admin");
        if (raw) {
          const draft = JSON.parse(raw);
          const draftContent = draft?.contentEN || draft?.CONTENT?.contentEN;
          if (draftContent) {
            baseContent = lang === "en" ? draftContent : (draft.contentVN || draft.CONTENT.contentVN);
          }
        }
      } catch (e) { console.error("CMS Preview Error:", e); }

      const allEvents = baseContent?.pages?.landing?.section?.eventContent?.events || [];
      const ev = allEvents.find((e: any) => e.slug === eventSlug && e.published);

      setEventData(ev || null);
      setLoading(false);
    };

    if (eventSlug) loadEvent();
  }, [eventSlug, content, lang]);

  const handleScrollToPricing = () => {
    const el = document.getElementById("pricing");
    if (el) el.scrollIntoView({ behavior: "smooth" });
  };

  if (loading) {
    return (
      <main
        style={{
          background: "#1A202C",
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "#fff",
        }}
      >
        <Header content={content?.pages?.globals?.section?.headerContent} />
        <div>Loading event details...</div>
        <Footer content={content?.pages?.globals?.section?.footerContent} />
      </main>
    );
  }

  if (!eventData) {
    return (
      <main
        style={{
          background: "#1A202C",
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <Header content={content?.pages?.globals?.section?.headerContent} />
        <div
          style={{
            color: "white",
            textAlign: "center",
            padding: "2rem",
          }}
        >
          <h1
            style={{
              fontSize: "2rem",
              marginBottom: "1rem",
              color: "#D4A017",
            }}
          >
            Event Not Found
          </h1>
          <p>The event you’re looking for doesn’t exist or is not published yet.</p>
        </div>
        <Footer content={content?.pages?.globals?.section?.footerContent} />
      </main>
    );
  }

  const isCheckout = location.pathname.endsWith("/checkout");

  if (isCheckout) {
    return (
      <main style={{ background: "#1A202C", minHeight: "100vh" }}>
        <Header content={content?.pages?.globals?.section?.headerContent} />
        <CheckOut eventData={eventData} />
        <Footer content={content?.pages?.globals?.section?.footerContent} />
      </main>
    );
  }

  return (
    <main style={{ background: "#1A202C", minHeight: "100vh" }}>
      <Header content={content?.pages?.globals?.section?.headerContent} />
      <EventHero
        eventName={eventData.info?.eventName || eventData.eventName}
        eventDate={eventData.info?.eventDate || eventData.date}
        countdownDate={eventData.info?.countdownDate}
        location={eventData.info?.location || "TBA"}
        remainingTickets={eventData.info?.remainingTickets || 0}
        speakersCount={eventData.info?.speakersCount || eventData.speakers?.list?.length || 0}
        bgImage={eventData.hero?.bgImage}
        onRegisterClick={handleScrollToPricing}
      />
      <EventSection data={eventData.about || { description: "Event details coming soon." }} />
      <EventSpeakers speakers={eventData.speakers?.list || eventData.speakers || []} />
      <TestimonialsSection testimonials={eventData.testimonials?.list || eventData.testimonials || []} />
      <PriceList
        pricing={eventData.pricing || []}
        checkoutData={eventData.checkout}
        successData={eventData.success}
      />
      <EventAttendees attendees={eventData.attendees?.list || eventData.attendees || []} />
      <Footer content={content?.pages?.globals?.section?.footerContent} />
    </main>
  );
};

export default DynamicEventPage;

export const Head = ({ location }: { location: { pathname: string } }) => {
  const eventSlug = location.pathname.split("/")[2];
  return (
    <>
      <title>{eventSlug ? `${eventSlug} - Event` : "Event"} | Tinh Hoa Việt</title>
      <meta name="description" content={`Information and registration for ${eventSlug}`} />
    </>
  );
};
